var e=[{id:`L2_1`,type:`dialog`,speaker:`PMC_NPC_TYPEB_NULL`,text:{KOREA:`꼬마야, 조심해!`,JPN:`お嬢ちゃん、気を付けろ！`,ENG:`Watch out, kid!`,TWN:`小傢伙，小心！`},stage:{bg:`ROOFTOP`,slots:{L:null,C:{char_id:`PMC_NPC_TYPEB_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L7_1`,type:`dialog`,speaker:`DASH_HORIZON_NULL_NULL`,text:{KOREA:`고마워요!`,JPN:`ありがとうございます！`,ENG:`Thanks!`,TWN:`謝謝！`},stage:{bg:`ROOFTOP`,slots:{L:null,C:{char_id:`DASH_HORIZON_NULL_NULL`,face:`UNIT_LAUGH`},R:null}}},{id:`L8_1`,type:`dialog`,speaker:`DASH_HORIZON_NULL_NULL`,text:{KOREA:`그리고 대장님도요! 하앗!`,JPN:`隊長さんも気を付けてくださいね！　はっ！`,ENG:`You too, Captain! Hiyah!`,TWN:`隊長也是哦！哈啊！`},stage:{bg:`ROOFTOP`,slots:{L:null,C:{char_id:`DASH_HORIZON_NULL_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L15_1`,type:`dialog`,speaker:`PMC_NPC_TYPEB_NULL`,text:{KOREA:`휴우, 카운터가 같이 싸워 주니까 든든하네.`,JPN:`ふう、カウンターが一緒に戦ってくれるから心強いな。`,ENG:`Phew, it sure is reassuring to have a Counter backing us up.`,TWN:`呼，跟制裁者一起打仗還真踏實。`},stage:{bg:`ROOFTOP`,slots:{L:{char_id:`DASH_HORIZON_NULL_NULL`,face:`UNIT_LAUGH`},C:null,R:{char_id:`PMC_NPC_TYPEB_NULL`,face:`UNIT_IDLE`}}}},{id:`L16_1`,type:`dialog`,speaker:`DASH_HORIZON_NULL_NULL`,text:{KOREA:`헤헤, 칭찬 받았다. 리타 언니는 제가 맨날 걸리적거린다고 싫어하거든요.`,JPN:`へへっ、褒められちゃった。リタお姉ちゃんはいつも私のことを邪魔くさいって嫌がるんです。`,ENG:`Heh heh, thanks for the compliment! Rita always says I just get in her way.`,TWN:`嘿嘿，被誇獎嘍。麗塔姐姐之前還嫌棄我每天都扯後腿呢。`},stage:{bg:`ROOFTOP`,slots:{L:{char_id:`DASH_HORIZON_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`PMC_NPC_TYPEB_NULL`,face:`UNIT_IDLE`}}}},{id:`L17_1`,type:`dialog`,speaker:`PMC_NPC_TYPEB_NULL`,text:{KOREA:`뭐? 자기는 이럴 때 코빼기도 안 비치면서?`,JPN:`は？　自分はこんな時に顔も出さないくせに？`,ENG:`What? But she hasn't even showed her face in this crisis!`,TWN:`什麼？這種情況連個影子都沒看到的人，還好意思說你？`},stage:{bg:`ROOFTOP`,slots:{L:{char_id:`DASH_HORIZON_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`PMC_NPC_TYPEB_NULL`,face:`UNIT_IDLE`}}}},{id:`L18_1`,type:`dialog`,speaker:`DASH_HORIZON_NULL_NULL`,text:{KOREA:`언니는 싸우는 걸 별로 안 좋아하거든요.`,JPN:`リタお姉ちゃんは戦いがあまり好きじゃないんです。`,ENG:`She's not a big fan of fighting.`,TWN:`姐姐不怎麼喜歡打架。`},stage:{bg:`ROOFTOP`,slots:{L:{char_id:`DASH_HORIZON_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`PMC_NPC_TYPEB_NULL`,face:`UNIT_IDLE`}}}},{id:`L19_1`,type:`dialog`,speaker:`DASH_HORIZON_NULL_NULL`,text:{KOREA:`대표님 말로는 남들보다 CRF 소비가 많대요.`,JPN:`代表の話だと、他の人よりCRFの消費が多いらしくて。`,ENG:`The boss says she spends more CRF than others.`,TWN:`按我們家BOSS的話來說… 就是她會消耗比別人更多的CRF。`},stage:{bg:`ROOFTOP`,slots:{L:{char_id:`DASH_HORIZON_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`PMC_NPC_TYPEB_NULL`,face:`UNIT_IDLE`}}}},{id:`L20_1`,type:`dialog`,speaker:`PMC_NPC_TYPEB_NULL`,text:{KOREA:`흐음...... 난 카운터가 아니라 잘 모르겠지만 그건 핑계 같은데......`,JPN:`ふむ……俺はカウンターじゃないからよくわからんが、ただの言い訳に聞こえるな……`,ENG:`Hmm... I'm not a Counter, so I wouldn't know any better... but that just sounds like a lame excuse.`,TWN:`唔……你說的這個因為我不是制裁者也不是很懂，不過還是像藉口……`},stage:{bg:`ROOFTOP`,slots:{L:{char_id:`DASH_HORIZON_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`PMC_NPC_TYPEB_NULL`,face:`UNIT_IDLE`}}}},{id:`L23_1`,type:`dialog`,speaker:null,text:{KOREA:`11시 방향! 놈들이 또 떼거지로 몰려온다!`,JPN:`11時方向！　敵の群れが押し寄せてくるぞ！`,ENG:`11 o'clock! Another wave incoming!`,TWN:`11點方向！那些傢伙又衝過來了！`},stage:{bg:`ROOFTOP`,slots:{L:{char_id:`DASH_HORIZON_NULL_NULL`,face:`UNIT_SURPRISE`},C:null,R:{char_id:`PMC_NPC_TYPEB_NULL`,face:`UNIT_SURPRISE`}}}},{id:`L24_1`,type:`dialog`,speaker:null,text:{KOREA:`제길, 총알이 다 떨어졌어! 누가 좀 나눠 줘!`,JPN:`くそっ、弾切れだ！　誰か分けてくれ！`,ENG:`Darn it, I'm all out of ammo! Somebody hook me up!`,TWN:`該死，沒子彈了！誰分給我一點！`},stage:{bg:`ROOFTOP`,slots:{L:{char_id:`DASH_HORIZON_NULL_NULL`,face:`UNIT_SURPRISE`},C:null,R:{char_id:`PMC_NPC_TYPEB_NULL`,face:`UNIT_SURPRISE`}}}},{id:`L25_1`,type:`dialog`,speaker:`PMC_NPC_TYPEB_NULL`,text:{KOREA:`이런, 아직 끝이 아니었나!`,JPN:`しまった、まだ終わりじゃねえのか！`,ENG:`Oh gosh, it's not over yet?`,TWN:`真是的，沒完沒了！`},stage:{bg:`ROOFTOP`,slots:{L:{char_id:`DASH_HORIZON_NULL_NULL`,face:`UNIT_SURPRISE`},C:null,R:{char_id:`PMC_NPC_TYPEB_NULL`,face:`UNIT_SERIOUS`}}}},{id:`L26_1`,type:`dialog`,speaker:`DASH_HORIZON_NULL_NULL`,text:{KOREA:`엄호해 주세요! 저도 다른 분들을 지켜 드릴게요!`,JPN:`援護お願いします！　私も他の方を守ります！`,ENG:`Cover me! I'll keep the others safe!`,TWN:`掩護我！我還要保護其他人！`},stage:{bg:`ROOFTOP`,slots:{L:{char_id:`DASH_HORIZON_NULL_NULL`,face:`UNIT_SERIOUS`},C:null,R:{char_id:`PMC_NPC_TYPEB_NULL`,face:`UNIT_SERIOUS`}}}},{id:`L29_1`,type:`dialog`,speaker:`PMC_NPC_TYPEB_NULL`,text:{KOREA:`어? 저건......?`,JPN:`あれ？　あれは……？`,ENG:`Huh? Isn't that...`,TWN:`額？那是……？`},stage:{bg:`SKY`,slots:{L:null,C:{char_id:`RITA_HORIZON_NULL_ON`,face:`UNIT_IDLE`},R:null}}},{id:`L30_1`,type:`dialog`,speaker:`DASH_HORIZON_NULL_NULL`,text:{KOREA:`리타 언니예요!`,JPN:`リタお姉ちゃんです！`,ENG:`It's Rita!`,TWN:`是麗塔姐姐！`},stage:{bg:`SKY`,slots:{L:null,C:{char_id:`RITA_HORIZON_NULL_ON`,face:`UNIT_IDLE`},R:null}}}];export{e as default};